Code:
public boolean xyBalance(String str) {
    int yCount = 0;
    for (int i = 0; i < str.length(); i++) {
        char currChar = str.charAt(i);
        if (currChar == 'x') {
            yCount = 0;
        } else if (currChar == 'y') {
            yCount++;
        }
        if (yCount == 0 && currChar != 'x') {
            return false;
        }
    }
    return yCount > 0;
}

