public int[] withoutTen(int[] nums) {
    int[] result = new int[nums.length];
    int j = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] != 10) {
            result[j] = nums[i];
            j++;
        }
    }
    return result;
}
